import {
  Button,
  Checkbox,
  Grid,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Typography,
} from '@material-ui/core';
import {
  CloudDownload,
  Refresh,
  ExpandLess,
  ExpandMore,
  UnfoldMore,
} from '@material-ui/icons';

import { useDebounce, useRequest } from 'ahooks';
import { format } from 'date-fns';
import fileDownload from 'js-file-download';
import { useSnackbar } from 'notistack';
import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';

import { useAPI, useHttpResource } from '../api/API';
import { useAppLanguage } from '../i18n/hooks';

import { ExportToFileDialog } from './ExportToFileDialog';
import { TableWrapper } from './TableWrapper';

export function ProductCatalogDataTable(props) {
  const { t } = useTranslation();
  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);
  const [selectedRowIds, setSelectedRowIds] = useState([]);
  const [filterHeader, setFilterHeader] = useState({ column: '', order: '' });

  const api = useAPI();

  const [currentLanguage] = useAppLanguage();
  const { enqueueSnackbar } = useSnackbar();

  const exportRequest = useRequest(
    (filename) =>
      api.requestJSON(
        'POST',
        props.export_url || `${props.resource_url}export/`,
        {
          data: {
            filename,
            file_type: 'csv',
          },
        }
      ),
    {
      manual: true,
      onSuccess: (data, [filename]) => {
        fileDownload(data, `${filename}.csv`);
      },
      onError: (e) => {
        if (e) {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const message = e.message;

          enqueueSnackbar(message[currentLanguage], {
            variant: 'error',
            preventDuplicate: true,
            key: message[currentLanguage],
          });
        }
      },
    }
  );
  const results = useHttpResource(props.resource_url);

  return (
    <>
      <ExportToFileDialog
        open={isExportDialogOpen}
        isLoading={exportRequest.loading}
        onClose={() => {
          setIsExportDialogOpen(false);
        }}
        onSave={(filename) => {
          exportRequest.run(filename);
        }}
      />

      <Grid container direction="column" spacing={2} wrap="nowrap">
        <Grid item container spacing={2} alignItems="center">
          <Grid item container sm spacing={2} alignItems="center">
            <Button variant="outlined">Skin Products</Button>
            <Button variant="outlined">Hair Products</Button>
            <Button variant="outlined">Nail Products</Button>
          </Grid>

          {props.toolbar?.export && (
            <Grid item>
              <Grid container spacing={2}>
                <Grid item>
                  <Button
                    onClick={() => {
                      results.revalidate();
                    }}
                    disabled={results.isValidating}
                    variant="outlined"
                    startIcon={<Refresh />}
                  >
                    {t('datatable.refresh')}
                  </Button>
                </Grid>
                <Grid item>
                  <Button
                    variant="outlined"
                    disabled={results.isValidating}
                    startIcon={<CloudDownload />}
                    onClick={() => {
                      setIsExportDialogOpen(true);
                    }}
                  >
                    {t('datatable.export')}
                  </Button>
                </Grid>
              </Grid>
            </Grid>
          )}
        </Grid>

        <Grid item xs>
          <TableWrapper
            style={{
              maxHeight: '100%',
              overflow: 'hidden',
              overflowX: 'initial',
              position: 'relative',
            }}
            isLoading={results.isValidating}
          >
            <Table size="small" aria-label="a dense table">
              <TableHead>
                <TableRow>
                  {!props.disableCheckbox && (
                    <TableCell>
                      <Checkbox
                        color="primary"
                        indeterminate={
                          selectedRowIds?.length > 0 &&
                          selectedRowIds?.length !== results.data?.data?.length
                        }
                        checked={
                          selectedRowIds?.length ===
                            results.data?.data?.length &&
                          selectedRowIds?.length > 0
                        }
                        onChange={(_, checked) => {
                          if (checked) {
                            setSelectedRowIds(
                              results.data?.data?.map(
                                (r) => r[props.dataIndex]
                              ) || []
                            );
                          } else {
                            setSelectedRowIds([]);
                          }
                        }}
                      />
                    </TableCell>
                  )}
                  {props.columns.map(
                    ({ label, key, hide }) =>
                      !hide && (
                        <TableCell key={key}>
                          <div
                            style={{
                              display: 'flex',
                              alignItems: 'center',
                              cursor: 'pointer',
                            }}
                          >
                            {label}
                            {filterHeader.column !== key && (
                              <div
                                style={{
                                  marginLeft: 10 + 'px',
                                  display: 'flex',
                                  flexDirection: 'column',
                                }}
                              >
                                <UnfoldMore
                                  color="disabled"
                                  fontSize={'small'}
                                />
                              </div>
                            )}
                            {filterHeader.column === key &&
                              filterHeader.order === 'asc' && (
                                <ExpandLess fontSize={'small'} />
                              )}
                            {filterHeader.column === key &&
                              filterHeader.order === 'desc' && (
                                <ExpandMore fontSize={'small'} />
                              )}
                          </div>
                        </TableCell>
                      )
                  )}
                </TableRow>
              </TableHead>

              <TableBody>
                {results.data?.count === 0 && (
                  <TableRow>
                    <TableCell colSpan={12} size="medium">
                      <Typography align="center" color="textSecondary">
                        {t('no_data')}
                      </Typography>
                    </TableCell>
                  </TableRow>
                )}

                {!results.data ? (
                  <TableRow>
                    <TableCell colSpan={12} size="medium">
                      <Typography align="center" color="textSecondary">
                        {t('loading')}
                      </Typography>
                    </TableCell>
                  </TableRow>
                ) : (
                  (props.normalize
                    ? props.normalize(results.data?.data)
                    : results.data?.data
                  )?.map((record, idx) => (
                    // eslint-disable-next-line react/no-array-index-key
                    <TableRow key={idx}>
                      {!props.disableCheckbox && (
                        <TableCell>
                          <Checkbox
                            color="primary"
                            checked={selectedRowIds?.includes(
                              record[props.dataIndex]
                            )}
                            onChange={(_, checked) => {
                              if (checked) {
                                setSelectedRowIds([
                                  ...(selectedRowIds || []),
                                  record[props.dataIndex],
                                ]);
                              } else {
                                setSelectedRowIds(
                                  selectedRowIds?.filter(
                                    (r) => r !== record[props.dataIndex]
                                  )
                                );
                              }
                            }}
                          />
                        </TableCell>
                      )}
                      {props.columns.map(
                        ({ key, content, hide }, index) =>
                          !hide && (
                            <TableCell key={key || index}>
                              {content ? content?.(record) : record[key]}
                            </TableCell>
                          )
                      )}
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </TableWrapper>
        </Grid>
      </Grid>
    </>
  );
}
